// ── Obtener filas de ambos tabs ──────────────────────────────────────────
const cfg      = $('Config Cliente').first().json;
const actual   = $('Sheet Actual').all().map(i => i.json);
const anterior = $('Sheet Anterior').all().map(i => i.json);

// ── Helpers ───────────────────────────────────────────────────────────────
const parseNum = str => {
  if (!str && str !== 0) return 0;
  const s = String(str).replace(/[$%\s]/g, '').replace(/\./g, '').replace(',', '.');
  return parseFloat(s) || 0;
};

// Woowup puede enviar porcentajes como 0.245 (decimal) o 24.5 (directo)
const parseRate = str => {
  const s = String(str || '0').replace('%', '').trim();
  const n = parseFloat(s.replace(',', '.')) || 0;
  return (n > 0 && n < 1) ? n * 100 : n;
};

const fmtNum   = n => Math.round(n).toLocaleString('es-AR');
const fmtPct   = n => n.toFixed(1).replace('.', ',') + '%';
const fmtMoney = n => '$' + Math.round(n).toLocaleString('es-AR');

const getField = (row, ...keys) => {
  for (const k of keys) {
    if (row[k] !== undefined && row[k] !== null && row[k] !== '') return row[k];
  }
  return undefined;
};

// ── Calcular totales de un conjunto de filas ──────────────────────────────
const calcTotals = rows => {
  let totalEnvios = 0, totalTrans = 0, totalIngresos = 0;
  let sumAperturaW = 0, sumCtorW = 0, sumBajasW = 0;

  rows.forEach(r => {
    const envios   = parseNum(getField(r, 'Delivered', 'Enviados', 'delivered'));
    const apertura = parseRate(getField(r, 'Open Rate', 'Tasa de apertura', 'open_rate'));
    const ctor     = parseRate(getField(r, 'CTOR', 'ctor'));
    const bajas    = parseRate(getField(r, 'Unsubscribe Rate', 'Tasa de bajas', 'unsubscribe_rate'));
    const trans    = parseNum(getField(r, 'Transacciones online', 'Transacciones', 'transacciones') || 0);
    const ingresos = parseNum(getField(r, 'Ingresos online', 'Ingresos', 'ingresos') || 0);

    totalEnvios   += envios;
    totalTrans    += trans;
    totalIngresos += ingresos;
    sumAperturaW  += apertura * envios;
    sumCtorW      += ctor     * envios;
    sumBajasW     += bajas    * envios;
  });

  return {
    envios:        totalEnvios,
    apertura:      totalEnvios > 0 ? sumAperturaW / totalEnvios : 0,
    ctor:          totalEnvios > 0 ? sumCtorW     / totalEnvios : 0,
    bajas:         totalEnvios > 0 ? sumBajasW    / totalEnvios : 0,
    transacciones: totalTrans,
    ingresos:      totalIngresos,
  };
};

// ── Calcular delta ────────────────────────────────────────────────────────
const delta = (curr, prev, isRate = false) => {
  if (!prev || prev === 0) return { str: '—', up: true };
  if (isRate) {
    const diff = curr - prev;
    return { str: (diff >= 0 ? '+' : '') + diff.toFixed(1).replace('.', ',') + 'pp', up: diff >= 0 };
  }
  const pct = (curr - prev) / prev * 100;
  return { str: (pct >= 0 ? '+' : '') + pct.toFixed(0) + '%', up: pct >= 0 };
};

// ── Procesar períodos ─────────────────────────────────────────────────────
const a = calcTotals(actual);
const p = calcTotals(anterior);

const dEnvios   = delta(a.envios,        p.envios);
const dApertura = delta(a.apertura,      p.apertura,      true);
const dCtor     = delta(a.ctor,          p.ctor,          true);
const dBajas    = delta(a.bajas,         p.bajas,         true);
const dTrans    = delta(a.transacciones, p.transacciones);
const dIngresos = delta(a.ingresos,      p.ingresos);

// ── Array de campañas (max 10, orden por envíos desc) ─────────────────────
const hasTrans    = actual.some(r => parseNum(getField(r, 'Transacciones online', 'transacciones') || 0) > 0);
const hasIngresos = actual.some(r => parseNum(getField(r, 'Ingresos online', 'ingresos') || 0) > 0);

const campanas = actual
  .map(r => {
    const enviosRaw = parseNum(getField(r, 'Delivered', 'Enviados', 'delivered'));
    const obj = {
      nombre:   String(getField(r, 'Campaña', 'Campaign', 'campaña', 'campaign') || ''),
      envios:   fmtNum(enviosRaw),
      apertura: fmtPct(parseRate(getField(r, 'Open Rate', 'open_rate'))),
      ctor:     fmtPct(parseRate(getField(r, 'CTOR', 'ctor'))),
      bajas:    fmtPct(parseRate(getField(r, 'Unsubscribe Rate', 'unsubscribe_rate'))),
      _raw:     enviosRaw,
    };
    if (hasTrans)    obj.transacciones = fmtNum(parseNum(getField(r, 'Transacciones online', 'transacciones') || 0));
    if (hasIngresos) obj.ingresos      = fmtMoney(parseNum(getField(r, 'Ingresos online', 'ingresos') || 0));
    return obj;
  })
  .sort((x, y) => y._raw - x._raw)
  .slice(0, 10)
  .map(({ _raw, ...rest }) => rest);

// ── Armar DATA ────────────────────────────────────────────────────────────
const DATA = {
  CLIENTE_NOMBRE:         cfg.CLIENTE_NOMBRE         || '',
  CLIENTE_LOGO_URL:       cfg.CLIENTE_LOGO_URL        || '',
  PERIODO_ACTUAL_LABEL:   cfg.PERIODO_ACTUAL_LABEL    || '',
  PERIODO_ANTERIOR_LABEL: cfg.PERIODO_ANTERIOR_LABEL  || '',
  WEB:                    cfg.WEB                     || '',
  CONTACTO:               cfg.CONTACTO                || '',
  PLATAFORMA_EMAIL:       'Woowup',

  EMAIL_ENVIOS:          fmtNum(a.envios),
  EMAIL_ENVIOS_PREV:     fmtNum(p.envios),
  EMAIL_ENVIOS_DELTA:    dEnvios.str,
  EMAIL_ENVIOS_DELTA_UP: dEnvios.up,

  EMAIL_APERTURA:          fmtPct(a.apertura),
  EMAIL_APERTURA_PREV:     fmtPct(p.apertura),
  EMAIL_APERTURA_DELTA:    dApertura.str,
  EMAIL_APERTURA_DELTA_UP: dApertura.up,

  EMAIL_CTOR:          fmtPct(a.ctor),
  EMAIL_CTOR_PREV:     fmtPct(p.ctor),
  EMAIL_CTOR_DELTA:    dCtor.str,
  EMAIL_CTOR_DELTA_UP: dCtor.up,

  EMAIL_BAJAS:          fmtPct(a.bajas),
  EMAIL_BAJAS_PREV:     fmtPct(p.bajas),
  EMAIL_BAJAS_DELTA:    dBajas.str,
  EMAIL_BAJAS_DELTA_UP: dBajas.up,

  ...(a.transacciones > 0 ? {
    EMAIL_TRANSACCIONES:          fmtNum(a.transacciones),
    EMAIL_TRANSACCIONES_PREV:     fmtNum(p.transacciones),
    EMAIL_TRANSACCIONES_DELTA:    dTrans.str,
    EMAIL_TRANSACCIONES_DELTA_UP: dTrans.up,
  } : {}),

  ...(a.ingresos > 0 ? {
    EMAIL_INGRESOS:          fmtMoney(a.ingresos),
    EMAIL_INGRESOS_PREV:     fmtMoney(p.ingresos),
    EMAIL_INGRESOS_DELTA:    dIngresos.str,
    EMAIL_INGRESOS_DELTA_UP: dIngresos.up,
  } : {}),

  EMAIL_CAMPANAS:  campanas,
  GA4_TIENE_DATOS: false,

  RECOMENDACIONES: [],
};

return [{ json: { DATA } }];
